from typing import Optional

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def levelOrder(self, root: Optional[TreeNode]) -&gt; List[List[int]]:
        if not root:
            return []
        q = deque([root])
        ans = []
        while q:
            size = len(q)
            level = []
            for _ in range(size):
                node = q.popleft()
                level.append(node.val)
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
            ans.append(level)
        return ans
</code></pre> <pre><code>struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int x = 0, TreeNode* l = nullptr, TreeNode* r = nullptr) : val(x), left(l), right(r) {}
};

class Solution {
public:
    vector&lt;vector&lt;int&gt;&gt; levelOrder(TreeNode* root) {
        if (!root) return {};
        queue&lt;TreeNode*&gt; q;
        q.push(root);
        vector&lt;vector&lt;int&gt;&gt; ans;
        while (!q.empty()) {
            int size = (int)q.size();
            vector&lt;int&gt; level;
            level.reserve(size);
            for (int i = 0; i &lt; size; ++i) {
                TreeNode* node = q.front();
                q.pop();
                level.push_back(node-&gt;val);
                if (node-&gt;left) q.push(node-&gt;left);
                if (node-&gt;right) q.push(node-&gt;right);
            }
            ans.push_back(move(level));
        }
        return ans;
    }
};
