Python3C++ <pre><code>from typing import Optional

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def buildTree(self, preorder: List[int], inorder: List[int]) -&gt; Optional[TreeNode]:
        pos = {v: i for i, v in enumerate(inorder)}

        def dfs(pl: int, pr: int, il: int, ir: int) -&gt; Optional[TreeNode]:
            if pl &gt; pr:
                return None
            root_val = preorder[pl]
            k = pos[root_val]
            left_size = k - il
            root = TreeNode(root_val)
            root.left = dfs(pl + 1, pl + left_size, il, k - 1)
            root.right = dfs(pl + left_size + 1, pr, k + 1, ir)
            return root

        return dfs(0, len(preorder) - 1, 0, len(inorder) - 1)
</code></pre> <pre><code>struct TreeNode {
