    TreeNode* dfs(vector&lt;int&gt;&amp; pre, int pl, int pr, int il, int ir) {
        if (pl &gt; pr) return nullptr;
        int root_val = pre[pl];
        int k = pos[root_val];
        int left_size = k - il;
        TreeNode* root = new TreeNode(root_val);
        root-&gt;left = dfs(pre, pl + 1, pl + left_size, il, k - 1);
        root-&gt;right = dfs(pre, pl + left_size + 1, pr, k + 1, ir);
        return root;
    }

    TreeNode* buildTree(vector&lt;int&gt;&amp; preorder, vector&lt;int&gt;&amp; inorder) {
        for (int i = 0; i &lt; (int)inorder.size(); ++i) pos[inorder[i]] = i;
        return dfs(preorder, 0, (int)preorder.size() - 1, 0, (int)inorder.size() - 1);
    }
};
