Python3C++ <pre><code>class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def sortList(self, head: ListNode) -&gt; ListNode:
        if not head or not head.next:
            return head
        slow, fast = head, head.next
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
        mid = slow.next
        slow.next = None
        l = self.sortList(head)
        r = self.sortList(mid)
        dummy = ListNode()
        cur = dummy
        while l and r:
            if l.val &lt;= r.val:
                cur.next = l
                l = l.next
            else:
                cur.next = r
                r = r.next
            cur = cur.next
        cur.next = l if l else r
        return dummy.next
</code></pre> <pre><code>struct ListNode {
    int val;
