            if (!g.count(s) || !g.count(t)) return -1.0;
            if (s == t) return 1.0;
            queue&lt;pair&lt;string, double&gt;&gt; q;
            unordered_set&lt;string&gt; vis;
            q.push({s, 1.0});
            vis.insert(s);
            while (!q.empty()) {
                auto [x, w] = q.front();
                q.pop();
                if (x == t) return w;
                for (auto&amp; [y, k] : g[x]) {
                    if (!vis.count(y)) {
                        vis.insert(y);
                        q.push({y, w * k});
                    }
                }
            }
            return -1.0;
        };

        vector&lt;double&gt; ans;
        for (auto&amp; q : queries) ans.push_back(bfs(q[0], q[1]));
